/**
 * Ley 24.013 (1991) — Ley Nacional de Empleo. VIGENTE (con varios títulos derogados:
 * las modalidades promovidas de contratación del Título III fueron derogadas por las
 * leyes 24.465 y 25.013).
 *
 * Fuente oficial: https://www.argentina.gob.ar/normativa/nacional/ley-24013-412/texto
 * Texto original literal (BO 17/12/1991).
 */
import type { Law, Article } from '../common/types/law.types';

const LAW_ID = 'ley-24013';

function art(number: string, title: string, text: string, explanation: string): Article {
  const id = `${LAW_ID}-art-${number}`;
  return {
    id, lawId: LAW_ID, number, title, text,
    plainLanguageExplanation: explanation,
    practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [],
    regulations: [], keywords: [], order: Number(number),
    segments: [{
      id: `${id}-s1`, lawId: LAW_ID, articleId: id, articleNumber: number,
      segmentType: 'PARAGRAPH', text, plainExplanation: explanation,
      practicalExample: null, references: [], order: 0,
    }],
    amendments: [],
  };
}

const ARTICULOS: Article[] = [
  art('1', 'La política de empleo',
    `Las acciones del Poder Ejecutivo dirigidas a mejorar la situación socioeconómica de la población adoptarán como un eje principal la política de empleo, entendido éste como situación social jurídicamente configurada. Dicha política, que a través de los mecanismos previstos en esta ley tiende a hacer operativo el derecho constitucional a trabajar, integra en forma coordinada las políticas económico sociales.`,
    `Pone a la política de empleo como eje de la acción del Estado, para hacer efectivo el derecho constitucional a trabajar.`),
  art('2', 'Objetivos de la ley',
    `Son objetivos de esta ley: a) Promover la creación del empleo productivo; b) Prevenir y regular las repercusiones de los procesos de reconversión productiva y de reforma estructural sobre el empleo; c) Inducir la transferencia de personas de actividades de baja productividad a otras de mayor productividad; d) Fomentar las oportunidades de empleo para los grupos con mayores dificultades de inserción laboral; e) Incorporar la formación profesional como componente básico; f) Promover el incremento de la producción y la productividad; g) Atender la movilidad sectorial y geográfica de la mano de obra; h) Organizar un sistema eficaz de protección a los trabajadores desocupados; i) Establecer mecanismos para el salario mínimo, vital y móvil; j) Promover la regularización de las relaciones laborales, desalentando las prácticas evasoras; k) Implementar mecanismos de participación tripartita y federal.`,
    `Enumera los objetivos de la ley: crear empleo productivo, proteger a los desocupados, fomentar la formación profesional, regularizar el empleo no registrado y operar el salario mínimo, vital y móvil.`),
  art('3', 'Contenido de la política de empleo',
    `La política de empleo comprende las acciones de prevención y sanción del empleo no registrado, de servicios de empleo, de promoción y defensa del empleo, de protección a trabajadores desempleados, de formación y orientación profesional para el empleo y las demás previstas en esta ley. Su formulación y ejecución es misión del Poder Ejecutivo a través de la acción coordinada de sus distintos organismos.`,
    `Define qué abarca la política de empleo: combatir el trabajo en negro, los servicios de empleo, la protección al desempleado y la formación profesional.`),
  art('4', 'Funciones en materia de empleo (Ley de Ministerios)',
    `Inclúyense como incisos 21, 22 y 23 del artículo 23 de la Ley de Ministerios (t.o. 1983): 21. Entender en la elaboración de políticas y programas de empleo. 22. Entender en la elaboración de estadísticas, estudios y encuestas sobre el empleo, la formación profesional y los ingresos. 23. Intervenir en la definición de los censos y encuestas oficiales en lo referente al empleo.`,
    `Suma a las funciones del Ministerio de Trabajo (en la Ley de Ministerios) las políticas de empleo y las estadísticas laborales.`),
  art('5', 'Autoridad de aplicación',
    `El Ministerio de Trabajo y Seguridad Social será la autoridad de aplicación de esta ley y deberá elaborar regularmente el Plan Nacional de Empleo y Formación Profesional. Asimismo, podrá delegar las facultades de policía mediante convenios celebrados con las provincias.`,
    `El Ministerio de Trabajo aplica la ley y elabora el Plan Nacional de Empleo, pudiendo delegar el control en las provincias.`),
  art('6', 'Coordinación interministerial',
    `El Poder Ejecutivo, a propuesta del Ministerio de Trabajo y Seguridad Social, establecerá un mecanismo de coordinación interministerial para facilitar la aplicación de esta ley que asegure una fluida información, la adopción de criterios comunes y una adecuada ejecución de las medidas.`,
    `Crea una coordinación entre ministerios para aplicar la política de empleo de forma articulada.`),
  art('7', 'Cuándo se considera registrada una relación laboral',
    `Se entiende que la relación o contrato de trabajo ha sido registrado cuando el empleador hubiere inscripto al trabajador: a) En el libro especial del artículo 52 de la Ley de Contrato de Trabajo (t.o. 1976) o en la documentación laboral que haga sus veces; b) En los registros mencionados en el artículo 18, inciso a). Las relaciones laborales que no cumplieren con los requisitos fijados en los incisos precedentes se considerarán no registradas.`,
    `Define cuándo un trabajo está "en blanco": cuando el empleador inscribió al trabajador en el libro de sueldos y en los registros de la seguridad social. Si no, es trabajo NO registrado (en negro).`),
  art('8', 'Indemnización por falta de registración',
    `El empleador que no registrare una relación laboral abonará al trabajador afectado una indemnización equivalente a una cuarta parte de las remuneraciones devengadas desde el comienzo de la vinculación, computadas a valores reajustados de acuerdo a la normativa vigente. En ningún caso esta indemnización podrá ser inferior a tres veces el importe mensual del salario que resulte de la aplicación del artículo 245 de la Ley de Contrato de Trabajo (t.o. 1976).`,
    `Es una de las multas más importantes contra el trabajo en negro: si el empleador nunca registró al trabajador, debe pagarle el 25% de todo lo que cobró durante la relación (con un mínimo de 3 sueldos). Es la "indemnización por trabajo no registrado".`),
  art('9', 'Indemnización por fecha de ingreso falsa',
    `El empleador que consignare en la documentación laboral una fecha de ingreso posterior a la real, abonará al trabajador afectado una indemnización equivalente a la cuarta parte del importe de las remuneraciones devengadas desde la fecha de ingreso hasta la fecha falsamente consignada, computadas a valores reajustados.`,
    `Si el empleador registró al trabajador pero con una fecha de ingreso más tardía que la real (para ocultar parte de la antigüedad), debe pagarle el 25% de los sueldos de ese período no registrado.`),
  art('10', 'Indemnización por remuneración menor a la real',
    `El empleador que consignare en la documentación laboral una remuneración menor que la percibida por el trabajador, abonará a éste una indemnización equivalente a la cuarta parte del importe de las remuneraciones devengadas y no registradas, debidamente reajustadas desde la fecha en que comenzó a consignarse indebidamente el monto.`,
    `Si el empleador registra un sueldo menor al que realmente paga (el clásico "una parte en blanco y otra en negro"), debe pagar el 25% de la parte del sueldo que no registró.`),
  art('11', 'Requisitos para reclamar (intimación)',
    `Las indemnizaciones previstas en los artículos 8, 9 y 10 procederán cuando el trabajador o la asociación sindical que lo represente intime al empleador en forma fehaciente, a fin que proceda a la inscripción, establezca la fecha real de ingreso o el verdadero monto de las remuneraciones. Con la intimación el trabajador deberá indicar la real fecha de ingreso y las circunstancias verídicas. Si el empleador diera total cumplimiento dentro del plazo de los treinta (30) días, quedará eximido del pago de las indemnizaciones. Sólo se computarán remuneraciones devengadas hasta los dos (2) años anteriores a la entrada en vigencia de la ley.`,
    `Para cobrar estas multas, el trabajador debe intimar primero al empleador (por telegrama) a que lo registre o corrija la fecha o el sueldo. Si el empleador regulariza todo en 30 días, no paga la multa. Es el paso obligatorio para reclamar el trabajo en negro.`),
  art('12', 'Regularización espontánea del empleador',
    `El empleador que registrare espontáneamente y comunicare al trabajador dentro de los noventa (90) días de la vigencia de esta ley las relaciones laborales no registradas, quedará eximido del pago de los aportes, contribuciones, multas y recargos adeudados, incluyendo obras sociales. Igual eximición para quien rectificare la falsa fecha de ingreso o el verdadero monto de la remuneración. A los fines previsionales, las relaciones así registradas podrán computarse como tiempo de servicio pero no acreditarán aportes ni monto de remuneraciones.`,
    `Daba a los empleadores un blanqueo: si registraban espontáneamente al personal en negro dentro de los 90 días de la ley, no pagaban las deudas atrasadas de aportes ni multas. Es una disposición transitoria de 1991.`),
  art('13', 'Eximición de las indemnizaciones por regularización',
    `En los casos previstos en el artículo anterior el empleador quedará eximido del pago de las indemnizaciones que correspondieren por aplicación de los artículos 8, 9 y 10 de la presente ley.`,
    `Quien se acogía al blanqueo del art. 12 tampoco debía pagar las indemnizaciones por trabajo no registrado.`),
  art('14', 'No requiere extinción de la relación',
    `Para la percepción de las indemnizaciones previstas en los artículos 8, 9 y 10 de la presente ley, no será requisito necesario la previa extinción de la relación de trabajo.`,
    `Importante: el trabajador puede reclamar las multas por trabajo en negro sin necesidad de renunciar ni ser despedido; puede hacerlo estando todavía empleado.`),
  art('15', 'Duplicación de indemnizaciones por despido represalia',
    `Si el empleador despidiere sin causa justificada al trabajador dentro de los dos (2) años desde que se le hubiere cursado de modo justificado la intimación prevista en el artículo 11, el trabajador despedido tendrá derecho a percibir el doble de las indemnizaciones que le hubieren correspondido como consecuencia del despido. Si el empleador otorgare el preaviso, su plazo también se duplicará. La duplicación tendrá igualmente lugar cuando fuere el trabajador el que se considerare en situación de despido por causa vinculada a la falta de registración.`,
    `Protege al trabajador que reclamó: si el empleador lo despide sin causa dentro de los 2 años de haber intimado por el trabajo en negro, debe pagarle el DOBLE de la indemnización por despido. Desalienta el despido como represalia.`),
  art('16', 'Reducción judicial por duda razonable',
    `Cuando las características de la relación pudieran haber generado en el empleador una razonable duda acerca de la aplicación de la Ley de Contrato de Trabajo, el juez podrá reducir la indemnización prevista en el artículo 8 hasta una suma no inferior a dos veces el importe mensual del salario del artículo 245 de la LCT. Con igual fundamento los jueces podrán reducir el monto de la indemnización del artículo anterior hasta la eliminación de la duplicación.`,
    `Si había una duda razonable sobre si correspondía registrar la relación (por ejemplo, una relación que parecía autónoma), el juez puede reducir la multa, pero nunca por debajo de 2 sueldos.`),
  art('17', 'Pago solo ante autoridad y comunicación',
    `Será nulo y sin ningún valor todo pago por los conceptos indicados en los artículos 8, 9 y 10 que no se realizare ante la autoridad administrativa o judicial. Dentro de los diez (10) días hábiles siguientes a la resolución firme que reconozca el derecho, la autoridad deberá comunicar al Sistema Único de Registro Laboral (o al organismo previsional) los datos del empleador, el trabajador, las fechas de la vinculación y el monto de las remuneraciones. Constituirá falta grave del funcionario no cursar la comunicación.`,
    `El pago de estas multas solo vale si se hace ante la justicia o la autoridad laboral, y debe comunicarse al sistema de registro para que la relación quede blanqueada también frente a la seguridad social.`),
  art('18', 'Sistema Único de Registro Laboral',
    `El Sistema Único de Registro Laboral concentrará los siguientes registros: a) La inscripción del empleador y la afiliación del trabajador al Instituto Nacional de Previsión Social, a las cajas de subsidios familiares y a la obra social correspondiente; b) El registro de los contratos de trabajo bajo modalidades promovidas; c) El registro de los trabajadores beneficiarios del sistema integral de prestaciones por desempleo.`,
    `Crea un registro único que concentra la inscripción del trabajador en la seguridad social, los contratos promovidos y los beneficiarios del seguro de desempleo.`),
  art('19', 'Organización del Sistema Único de Registro Laboral',
    `El Poder Ejecutivo Nacional, a través del Ministerio de Trabajo y Seguridad Social, tendrá a su cargo la organización, conducción y supervisión del Sistema Único de Registro Laboral, con atribuciones para coordinar los organismos, elaborar el padrón único, aprobar los formularios, habilitar bocas de recepción, homogeneizar los sistemas informáticos, diseñar la boleta única de pago de aportes y contribuciones y establecer el código único de identificación laboral.`,
    `El Ministerio de Trabajo organiza ese registro único: arma el padrón, los formularios, la "boleta única" de aportes y el código único de identificación laboral (antecedente del CUIL).`),
  art('20', 'Aporte de datos al registro',
    `El Instituto Nacional de Previsión Social, las cajas de subsidios familiares y los entes de obras sociales deberán poner a disposición del Ministerio de Trabajo y Seguridad Social los datos y los medios necesarios para la creación y organización del Sistema Único de Registro Laboral.`,
    `Los organismos de la seguridad social deben darle al Ministerio de Trabajo los datos para armar el registro único.`),
  art('21', 'El empleo en las políticas nacionales',
    `El Poder Ejecutivo incorporará el criterio de la generación de empleo en el análisis y diseño de las políticas nacionales que tengan una incidencia significativa en el nivel y composición del empleo.`,
    `Manda tener en cuenta el impacto en el empleo al diseñar las políticas nacionales.`),
  art('22', 'Acciones para generar empleo',
    `A los efectos del artículo anterior, el Poder Ejecutivo instrumentará acciones dirigidas a: a) Elevar los niveles de utilización de la capacidad instalada; b) Facilitar la inversión productiva que genere impacto ocupacional; c) Exigir que los proyectos de inversión pública cuantifiquen sus efectos ocupacionales; d) Incluir proyectos de alta incidencia ocupacional en la inversión pública; e) Atender los efectos sobre el empleo de las políticas tecnológicas; f) Atenuar los efectos negativos en sectores en declinación; g) Asociar la capacitación laboral con el sistema productivo; h) Armonizar la fuerza de trabajo con el crecimiento.`,
    `Lista las acciones del Estado para fomentar el empleo: incentivar la inversión productiva, medir el impacto ocupacional de la obra pública y vincular la formación con la producción.`),
  art('23', 'Incorporación de tecnología',
    `La incorporación de tecnología constituye una condición para el crecimiento de la economía nacional. Es un derecho y una obligación del empresario que la ley reconoce, garantiza y estimula, y en la medida que afecta las condiciones de trabajo y empleo debe ser evaluada desde el punto de vista técnico, económico y social.`,
    `Reconoce la incorporación de tecnología como derecho y deber del empresario, evaluando su impacto en el empleo.`),
  art('24', 'Materias de negociación colectiva',
    `Las comisiones negociadoras de convenios colectivos tendrán obligación de negociar sobre: a) La incorporación de tecnología y sus efectos sobre el empleo; b) Sistemas de formación que faciliten la polivalencia; c) Los regímenes de categorías y la movilidad funcional; d) La relación entre productividad, producción y salarios reales; e) Las modalidades de contratación previstas en esta ley; f) Las consecuencias de los programas de reestructuración productiva; g) Mecanismos de información y consulta. La falta de conclusiones no impedirá la homologación del convenio.`,
    `Obliga a que en las negociaciones de convenios colectivos se traten temas como la tecnología, la formación, la movilidad funcional y la productividad, aunque no se llegue a acuerdo en todos.`),
  art('25', 'Modificación del art. 198 LCT (jornada reducida)',
    `Sustitúyese el artículo 198 de la Ley de Contrato de Trabajo (t.o. 1976) por lo siguiente: "Artículo 198. Jornada reducida. La reducción de la jornada máxima legal solamente procederá cuando lo establezcan las disposiciones nacionales reglamentarias de la materia, estipulación particular de los contratos individuales o convenios colectivos de trabajo. Estos últimos podrán establecer métodos de cálculo de la jornada máxima en base a promedio, de acuerdo con las características de la actividad."`,
    `Reformó el art. 198 de la Ley de Contrato de Trabajo: la jornada reducida procede según la ley, el contrato o el convenio, que puede calcular la jornada máxima por promedio.`),
  art('26', 'Derogación del art. 173 LCT',
    `Derógase el artículo 173 de la Ley de Contrato de Trabajo (t.o. 1976). En consecuencia denúnciense el Convenio Cuatro (4) y el Convenio Cuarenta y Uno (41) de la Organización Internacional del Trabajo, ratificados por las leyes 11.726 y 13.560, respectivamente.`,
    `Derogó el art. 173 de la LCT (que prohibía el trabajo nocturno de las mujeres en la industria) y denunció los convenios de la OIT correspondientes.`),
  art('27', 'Principio de indeterminación del plazo',
    `Ratifícase la vigencia del principio de indeterminación del plazo, como modalidad principal del contrato de trabajo, de acuerdo a lo establecido en el primer párrafo del artículo 90 de la ley 20.744 (t.o. 1976). Con relación a las modalidades de contratación previstas en esta ley, en caso de duda se considerará que el contrato es por tiempo indeterminado.`,
    `Ratifica que la regla es el contrato por tiempo indeterminado: ante la duda sobre una modalidad temporal, se considera que el contrato es por tiempo indeterminado.`),
  art('28', 'Modalidades promovidas y no promovidas (derogado)',
    `Las modalidades de contratación previstas en esta ley pueden ser promovidas o no promovidas. Son promovidas las de trabajo por tiempo determinado como medida de fomento del empleo, por lanzamiento de nueva actividad, de práctica laboral para jóvenes y de trabajo-formación. Son no promovidas las contrataciones de temporada y eventual.`,
    `[DEROGADO por la Ley 25.013] Clasificaba las modalidades de contratación de los años 90 en "promovidas" (contratos temporales con beneficios para el empleador) y "no promovidas".`),
  art('29', 'Igualdad de trato (derogado)',
    `Regirá el principio de igualdad de trato entre los trabajadores permanentes y los contratados bajo cualquiera de estas modalidades, debiendo ser los salarios, las condiciones de trabajo y las garantías iguales para todos los trabajadores de la misma actividad y categoría.`,
    `[DEROGADO por la Ley 25.013] Garantizaba que los contratados bajo modalidades promovidas tuvieran el mismo salario y condiciones que los permanentes.`),
  art('30', 'Habilitación por convenio colectivo (derogado)',
    `Las modalidades promovidas se habilitarán a través de las convenciones colectivas de trabajo, a cuyo efecto deberán reunirse las correspondientes comisiones negociadoras, las que deberán pronunciarse en noventa (90) días. Los acuerdos se formalizarán en un instrumento especial homologado por el Ministerio de Trabajo.`,
    `[DEROGADO por la Ley 25.013] Las modalidades promovidas debían habilitarse por convenio colectivo.`),
  art('31', 'Forma escrita y registro (derogado)',
    `Los contratos celebrados bajo las modalidades reguladas en este capítulo, salvo el de temporada, deberán instrumentarse por escrito y entregarse copias al trabajador y al sindicato en el plazo de treinta (30) días. Dentro del mismo plazo, el empleador deberá registrar los contratos promovidos en el registro del artículo 18 inciso b).`,
    `[DEROGADO por la Ley 25.013] Exigía que los contratos promovidos fueran por escrito y registrados en 30 días.`),
  art('32', 'Sin deudas previsionales (derogado)',
    `Para poder contratar bajo las modalidades promovidas, el empleador no deberá tener deudas exigibles con los organismos previsionales, de asignaciones familiares, obra social, FO.NA.VI., Fondo Nacional del Empleo y asociaciones sindicales.`,
    `[DEROGADO por la Ley 25.013] El empleador con deudas previsionales no podía usar las modalidades promovidas.`),
  art('33', 'Información al sindicato (derogado)',
    `En las empresas en las que se prevea adoptar las modalidades promovidas, la asociación sindical deberá ser informada por el empleador. La autoridad de aplicación verificará el cumplimiento de las condiciones de este capítulo.`,
    `[DEROGADO por la Ley 25.013] El empleador debía informar al sindicato el uso de modalidades promovidas.`),
  art('34', 'Tope porcentual (derogado)',
    `El número total de trabajadores contratados según las modalidades reguladas por este capítulo, salvo el de temporada, no podrá superar el treinta por ciento (30 %) del plantel permanente. En empresas de seis a veinticinco trabajadores el máximo será del cincuenta por ciento (50 %); con hasta cinco trabajadores, del cien por ciento (100 %), no pudiendo exceder de tres trabajadores.`,
    `[DEROGADO por la Ley 25.013] Limitaba la cantidad de trabajadores que se podían tomar bajo modalidades promovidas (en general, hasta el 30% del plantel).`),
  art('35', 'Conversión a tiempo indeterminado (derogado)',
    `Los contratos celebrados según las modalidades de este capítulo se convertirán en contratos por tiempo indeterminado cuando: a) no se cumplan los requisitos formales o sustanciales; b) no se cumpla el registro en 30 días; c) se exceda el plazo máximo; d) el trabajador continúe prestando servicios al vencimiento; e) se exceda el porcentaje permitido.`,
    `[DEROGADO por la Ley 25.013] Establecía cuándo un contrato promovido pasaba a ser por tiempo indeterminado (fraude, exceso de plazo, etc.).`),
  art('36', 'Exceso de plantel y prohibiciones (derogado)',
    `Los contratos bajo modalidades promovidas sólo podrán celebrarse cuando los nuevos contratados lo sean en exceso del plantel promedio de los últimos seis meses. No podrán contratar bajo estas modalidades las empresas que hayan producido despidos colectivos en los doce meses anteriores o que estén en conflicto colectivo. El empleador deberá abstenerse de despedir colectivamente durante los seis meses posteriores.`,
    `[DEROGADO por la Ley 25.013] Solo permitía contratos promovidos para sumar empleo (no reemplazar), y no a empresas que venían despidiendo.`),
  art('37', 'Preaviso en modalidades promovidas (derogado)',
    `El empleador que hubiera celebrado contratos bajo modalidades promovidas deberá preavisar con treinta (30) días la terminación del contrato o abonar una indemnización sustitutiva de medio mes de sueldo cuando el plazo no excediere de un año y de un mes cuando fuere superior.`,
    `[DEROGADO por la Ley 25.013] Fijaba el preaviso al terminar un contrato promovido.`),
  art('38', 'Indemnización al vencimiento (derogado)',
    `En los contratos bajo modalidades promovidas, salvo las de práctica laboral y trabajo-formación, la extinción al vencimiento del plazo dará lugar a una indemnización equivalente a medio salario mensual, que se acumulará a la sustitutiva del preaviso si no se hubiera otorgado.`,
    `[DEROGADO por la Ley 25.013] Reconocía media indemnización al terminar el contrato promovido por vencimiento.`),
  art('39', 'Ruptura sin causa (derogado)',
    `En las modalidades promovidas la ruptura del contrato sin causa justificada por parte del empleador dará lugar a la aplicación del primer párrafo del artículo 95 de la Ley de Contrato de Trabajo, con excepción de los contratos de práctica laboral y trabajo-formación.`,
    `[DEROGADO por la Ley 25.013] Si el empleador rompía sin causa un contrato promovido, debía los daños del art. 95 de la LCT.`),
  art('40', 'Sucesión de contratos (derogado)',
    `La celebración sucesiva de contratos bajo modalidades promovidas en exceso del plazo máximo, para cubrir un mismo puesto, convertirá al contrato en uno por tiempo indeterminado, salvo los contratos sucesivos de práctica laboral y de trabajo-formación. Respecto de las modalidades no promovidas regirá el capítulo I del Título III de la Ley de Contrato de Trabajo.`,
    `[DEROGADO por la Ley 25.013] Encadenar contratos promovidos para un mismo puesto los convertía en contrato por tiempo indeterminado.`),
  art('41', 'Obra social del trabajador contratado',
    `Los trabajadores contratados bajo cualquiera de las modalidades de esta ley deberán ser inscriptos en la obra social correspondiente al resto de los trabajadores de su categoría y actividad. La cobertura asistencial del trabajador y su grupo familiar comenzará desde el inicio de la relación laboral, sin período de carencia, conforme a las leyes 23.660 y 23.661.`,
    `Los trabajadores con contratos especiales tienen la misma obra social que el resto del plantel y cobertura desde el primer día, sin carencias (en línea con la Ley de Obras Sociales).`),
  art('42', 'Trabajadores con discapacidad (plazos)',
    `En el caso de que el trabajador a contratar acredite discapacidad, las modalidades de contratación de tiempo determinado como medida de fomento, por lanzamiento de nueva actividad, de práctica laboral, de trabajo-formación y a plazo fijo se duplicarán en sus plazos máximos de duración.`,
    `[En gran parte sin efecto tras la derogación de las modalidades promovidas] Duplicaba los plazos de los contratos especiales cuando el trabajador tenía discapacidad.`),
  art('43', 'Contrato de fomento del empleo (derogado)',
    `El contrato de trabajo de tiempo determinado como medida de fomento del empleo es celebrado por un empleador y un trabajador inscripto como desempleado en la Red de Servicios de Empleo o que haya dejado de prestar servicios en el sector público por racionalización administrativa.`,
    `[DEROGADO por la Ley 25.013] Era un contrato temporal para tomar desempleados registrados, con beneficios para el empleador.`),
  art('44', 'Plazo del contrato de fomento (derogado)',
    `El plazo mínimo de estos contratos será de seis (6) meses y el máximo no podrá exceder de dieciocho (18) meses, incluyendo las renovaciones, que serán por períodos de seis meses como mínimo.`,
    `[DEROGADO por la Ley 25.013] Plazo del contrato de fomento del empleo: de 6 a 18 meses.`),
  art('45', 'Puestos vacantes (derogado)',
    `Los puestos de trabajo permanentes que hubieran quedado vacantes durante los últimos seis meses no podrán ser cubiertos por personal contratado bajo esta modalidad, salvo acuerdo en negociación colectiva o habilitación administrativa.`,
    `[DEROGADO por la Ley 25.013] Impedía usar el contrato de fomento para cubrir puestos permanentes recién vacantes.`),
  art('46', 'Exención de contribuciones (derogado)',
    `El empleador será eximido del pago del cincuenta por ciento (50 %) de las contribuciones patronales por este tipo de contratos a las cajas de jubilaciones, al INSSJP, a las cajas de asignaciones y subsidios familiares, y al Fondo Nacional del Empleo.`,
    `[DEROGADO por la Ley 25.013] El gran incentivo del contrato de fomento: el empleador pagaba la mitad de las contribuciones patronales.`),
  art('47', 'Contrato por lanzamiento de nueva actividad (derogado)',
    `El contrato de trabajo de tiempo determinado por lanzamiento de nueva actividad es el celebrado entre un empleador y un trabajador para la prestación de servicios en un nuevo establecimiento o una nueva línea de producción de un establecimiento preexistente.`,
    `[DEROGADO por la Ley 25.013] Contrato temporal para personal de un nuevo establecimiento o línea de producción.`),
  art('48', 'Plazo del contrato por lanzamiento (derogado)',
    `El plazo mínimo de estos contratos será de seis (6) meses y el máximo no podrá exceder de veinticuatro (24) meses. Cualquiera sea la fecha de celebración, su vigencia cesará a los cuatro (4) años de iniciada la nueva actividad.`,
    `[DEROGADO por la Ley 25.013] Plazo del contrato por lanzamiento de nueva actividad: de 6 a 24 meses.`),
  art('49', 'Prohibición de despidos (lanzamiento) (derogado)',
    `El empleador deberá abstenerse de suspender o despedir colectivamente trabajadores de los antiguos establecimientos o líneas de producción durante el año posterior a estas contrataciones, salvo justa causa. La violación convertirá los acuerdos en contratos por tiempo indeterminado.`,
    `[DEROGADO por la Ley 25.013] Prohibía despedir del establecimiento viejo mientras se usaba el contrato por lanzamiento.`),
  art('50', 'Exención de contribuciones (lanzamiento) (derogado)',
    `El empleador será eximido del pago del cincuenta por ciento (50 %) de las contribuciones patronales por este tipo de contrato a las cajas de jubilaciones, al INSSJP, a las cajas de asignaciones y subsidios familiares, y al Fondo Nacional de Empleo.`,
    `[DEROGADO por la Ley 25.013] El incentivo del contrato por lanzamiento: la mitad de las contribuciones patronales.`),
  art('51', 'Contrato de práctica laboral para jóvenes (derogado)',
    `El contrato de práctica laboral para jóvenes es el celebrado entre empleadores y jóvenes de hasta 24 años de edad, con formación previa, en busca de su primer empleo para aplicar y perfeccionar sus conocimientos.`,
    `[DEROGADO por la Ley 25.013] Contrato para jóvenes con formación en busca del primer empleo.`),
  art('52', 'Plazo de la práctica laboral (derogado)',
    `El contrato de práctica laboral se celebrará por un (1) año.`,
    `[DEROGADO por la Ley 25.013] La práctica laboral duraba un año.`),
  art('53', 'Requisitos de la práctica laboral (derogado)',
    `Serán requisitos para celebrar estos contratos: a) Que los trabajadores acrediten formación técnica, profesional o laboral que los habilite, mediante certificación reconocida por el Ministerio de Trabajo; b) Que la práctica laboral sea adecuada a su nivel de formación.`,
    `[DEROGADO por la Ley 25.013] Requisitos del contrato de práctica laboral.`),
  art('54', 'Certificado de la práctica (derogado)',
    `En todos los casos el empleador extenderá un certificado a la conclusión del contrato, que acredite la experiencia adquirida en el puesto de trabajo, validado por la autoridad administrativa.`,
    `[DEROGADO por la Ley 25.013] El empleador debía dar un certificado de la experiencia.`),
  art('55', 'Jóvenes de 14 a 16 años (derogado)',
    `Los jóvenes de 14 a 16 años quedan sujetos a lo dispuesto por la Ley de Contrato de Trabajo (t.o. 1976), artículo 187, siguientes y concordantes, en todo lo que no sea expresamente modificado por esta ley.`,
    `[DEROGADO/desactualizado] Remitía al régimen de la LCT para menores (hoy la edad mínima de admisión al empleo es 16 años, ley 26.390).`),
  art('56', 'Extinción de la práctica laboral (derogado)',
    `Cuando el contrato cesare por cumplimiento del plazo del artículo 52, el empleador no estará obligado al pago de indemnización alguna, sin perjuicio de lo dispuesto en el artículo 37. En los otros supuestos regirá el artículo 245 y concordantes de la Ley de Contrato de Trabajo.`,
    `[DEROGADO por la Ley 25.013] Al terminar la práctica por plazo, no había indemnización.`),
  art('57', 'Exención de contribuciones (práctica) (derogado)',
    `Los empleadores que adopten esta modalidad quedan exentos por estos contratos de las contribuciones patronales a las cajas de jubilaciones, al INSSJP y a las cajas de asignaciones y subsidios familiares.`,
    `[DEROGADO por la Ley 25.013] El empleador se eximía de las contribuciones patronales por la práctica laboral.`),
  art('58', 'Contrato de trabajo-formación (derogado)',
    `El contrato de trabajo-formación es el celebrado entre empleadores y jóvenes de hasta 24 años de edad, sin formación previa, en busca de su primer empleo, con el fin de adquirir una formación teórico-práctica para desempeñarse en un puesto de trabajo.`,
    `[DEROGADO por la Ley 25.013] Contrato para jóvenes sin formación, que combinaba trabajo y capacitación.`),
  art('59', 'Plazo del trabajo-formación (derogado)',
    `El contrato de trabajo-formación tendrá un plazo de duración mínima de cuatro (4) meses y un máximo de dos (2) años.`,
    `[DEROGADO por la Ley 25.013] Duraba entre 4 meses y 2 años.`),
  art('60', 'Plan de alternancia (derogado)',
    `El Ministerio de Trabajo deberá formular el plan general de alternancia de formación y trabajo. El trabajo será realizado en la empresa; la formación podrá realizarse en la empresa o en un organismo de formación. Entre un cuarto y la mitad del tiempo deberá dedicarse a la formación.`,
    `[DEROGADO por la Ley 25.013] Repartía el tiempo entre trabajo y formación (entre 1/4 y 1/2 para formarse).`),
  art('61', 'Remuneración del trabajo-formación (derogado)',
    `La remuneración del tiempo de trabajo en la empresa estará a cargo del empleador. La remuneración del tiempo empleado en la formación estará a cargo del Fondo Nacional del Empleo, según la reglamentación.`,
    `[DEROGADO por la Ley 25.013] El empleador pagaba el tiempo de trabajo y el Fondo de Empleo el de formación.`),
  art('62', 'Certificado del trabajo-formación (derogado)',
    `En todos los casos el empleador extenderá un certificado a la conclusión del contrato que acredite la experiencia adquirida y la formación recibida, validado por la autoridad administrativa.`,
    `[DEROGADO por la Ley 25.013] Certificado de experiencia y formación.`),
  art('63', 'Jóvenes de 14 a 16 años (formación) (derogado)',
    `Los jóvenes de 14 a 16 años quedan sujetos a lo dispuesto por la Ley de Contrato de Trabajo (t.o. 1976), artículo 187, siguientes y concordantes, en todo lo que no sea expresamente modificado por esta ley.`,
    `[DEROGADO/desactualizado] Remitía al régimen de la LCT para menores.`),
  art('64', 'Extinción del trabajo-formación (derogado)',
    `El contrato cesará por cumplimiento del plazo pactado; en ese supuesto el empleador no estará obligado al pago de indemnización alguna, sin perjuicio del artículo 37. En los otros supuestos regirá el artículo 245 de la Ley de Contrato de Trabajo.`,
    `[DEROGADO por la Ley 25.013] Al terminar por plazo, sin indemnización.`),
  art('65', 'Exención de contribuciones (formación) (derogado)',
    `Los empleadores que adopten esta modalidad quedan exentos por estos contratos de las contribuciones patronales a las cajas de jubilaciones, al INSSJP y a las cajas de asignaciones y subsidios familiares.`,
    `[DEROGADO por la Ley 25.013] Eximía de contribuciones patronales el contrato de trabajo-formación.`),
  art('66', 'Contrato de temporada (modifica art. 96 LCT)',
    `Sustitúyese el artículo 96 de la Ley de Contrato de Trabajo (t.o. 1976) por el siguiente: "Artículo 96. Caracterización. Habrá contrato de Trabajo de Temporada cuando la relación entre las partes, originada por actividades propias del giro normal de la empresa o explotación, se cumpla en determinadas épocas del año solamente y esté sujeta a repetirse en cada ciclo en razón de la naturaleza de la actividad."`,
    `Reformó la definición del contrato de temporada en la LCT: es el de actividades que se cumplen solo en ciertas épocas del año y se repiten cada ciclo (cosecha, turismo, etc.). Sigue vigente.`),
  art('67', 'Contrato de temporada: convocatoria (modifica art. 98 LCT)',
    `Sustitúyese el artículo 98 de la Ley de Contrato de Trabajo por el siguiente: "Artículo 98. Con una antelación no menor a treinta (30) días respecto del inicio de cada temporada, el empleador deberá notificar a los trabajadores su voluntad de reiterar la relación. El trabajador deberá manifestar su decisión de continuar o no en un plazo de cinco (5) días de notificado. En caso que el empleador no cursara la notificación, se considerará que rescinde unilateralmente el contrato y responderá por las consecuencias de la extinción."`,
    `Reformó el art. 98 de la LCT: el empleador de temporada debe convocar al trabajador con 30 días de anticipación cada ciclo; si no lo hace, se considera que lo despidió. Sigue vigente.`),
  art('68', 'Contrato eventual (modifica art. 99 LCT)',
    `Sustitúyese el artículo 99 de la Ley de Contrato de Trabajo por el siguiente: "Artículo 99. Caracterización. Se considerará que media contrato de trabajo eventual cuando la actividad del trabajador se ejerce bajo la dependencia de un empleador para la satisfacción de resultados concretos, en relación a servicios extraordinarios determinados de antemano o exigencias extraordinarias y transitorias de la empresa, toda vez que no pueda preverse un plazo cierto para la finalización del contrato. El empleador que pretenda que el contrato inviste esta modalidad tendrá a su cargo la prueba de tal aseveración."`,
    `Reformó el art. 99 de la LCT: define el contrato eventual (para tareas extraordinarias y transitorias, sin plazo cierto). La carga de probar que es eventual recae en el empleador. Sigue vigente.`),
  art('69', 'Eventual por reemplazo',
    `Para el caso que el contrato de trabajo eventual tuviera por objeto sustituir transitoriamente trabajadores permanentes que gozaran de licencias o tuvieran reserva del puesto por plazo incierto, en el contrato deberá indicarse el nombre del trabajador reemplazado. Si al reincorporarse el reemplazado el contratado continuare prestando servicios, el contrato se convertirá en uno por tiempo indeterminado.`,
    `Cuando el eventual reemplaza a alguien con licencia, hay que poner el nombre del reemplazado; si este vuelve y el eventual sigue trabajando, el contrato pasa a ser por tiempo indeterminado.`),
  art('70', 'Prohibición: reemplazo de huelguistas',
    `Se prohíbe la contratación de trabajadores bajo esta modalidad para sustituir trabajadores que no prestaran servicios normalmente en virtud del ejercicio de medidas legítimas de acción sindical.`,
    `No se puede usar el contrato eventual para reemplazar a trabajadores en huelga.`),
  art('71', 'Prohibición tras despidos',
    `Las empresas que hayan producido suspensiones o despidos de trabajadores por falta o disminución de trabajo durante los seis (6) meses anteriores, no podrán ejercer esta modalidad para reemplazar al personal afectado por esas medidas.`,
    `Una empresa que despidió por falta de trabajo no puede tomar eventuales para cubrir esos mismos puestos durante 6 meses.`),
  art('72', 'Eventual por exigencias del mercado',
    `En los casos que el contrato tenga por objeto atender exigencias extraordinarias del mercado: a) En el contrato se consignará con precisión la causa que lo justifique; b) La duración de la causa no podrá exceder de seis (6) meses por año y hasta un máximo de un (1) año en un período de tres (3) años.`,
    `El eventual por un pico de demanda debe indicar la causa y no puede durar más de 6 meses por año (máximo 1 año en 3 años).`),
  art('73', 'Sin deber de preaviso',
    `El empleador no tiene el deber de preavisar la finalización del contrato.`,
    `En el contrato eventual no hace falta preavisar el fin del contrato.`),
  art('74', 'Sin indemnización al finalizar la causa',
    `No procederá indemnización alguna cuando la relación laboral se extinga con motivo de finalización de la obra o tarea asignada, o del cese de la causa que le diera origen. En cualquier otro supuesto, se estará a lo dispuesto en la Ley de Contrato de Trabajo.`,
    `Si el eventual termina porque terminó la tarea o la causa, no hay indemnización; en cualquier otro caso, se aplica la LCT.`),
  art('75', 'Empresas de servicios eventuales (modifica art. 29 LCT)',
    `Derógase el último párrafo del artículo 29 de la Ley de Contrato de Trabajo y se lo sustituye por el siguiente: "Los trabajadores contratados por empresas de servicios eventuales habilitadas por la autoridad competente para desempeñarse en los términos de los artículos 99 de la presente y 77 a 80 de la Ley Nacional de Empleo, serán considerados en relación de dependencia, con carácter permanente continuo o discontinuo, con dichas empresas."`,
    `Reformó la LCT: el trabajador de una agencia de personal eventual está en relación de dependencia permanente con la agencia. Sigue vigente.`),
  art('76', 'Responsabilidad solidaria (incorpora art. 29 bis LCT)',
    `Incorpórase como artículo 29 bis de la Ley de Contrato de Trabajo el siguiente: "Artículo 29 BIS. El empleador que ocupe trabajadores a través de una empresa de servicios eventuales habilitada será solidariamente responsable con aquella por todas las obligaciones laborales y deberá retener de los pagos que efectúe a la empresa de servicios eventuales los aportes y contribuciones para los organismos de la seguridad social. El trabajador estará regido por la convención colectiva, será representado por el sindicato y beneficiado por la obra social de la actividad en la que efectivamente preste servicios en la empresa usuaria."`,
    `Incorporó el art. 29 bis a la LCT: la empresa que usa personal de una agencia eventual es solidariamente responsable por las obligaciones laborales. Es una norma muy aplicada. Sigue vigente.`),
  art('77', 'Constitución de las empresas de servicios eventuales',
    `Las empresas de servicios eventuales deberán estar constituidas exclusivamente como personas jurídicas y con objeto único. Sólo podrán mediar en la contratación de trabajadores bajo la modalidad de trabajo eventual.`,
    `Las agencias de personal eventual deben ser sociedades con objeto único: solo pueden dedicarse a proveer trabajadores eventuales.`),
  art('78', 'Caución de las empresas de servicios eventuales',
    `Las empresas de servicios eventuales estarán obligadas a caucionar una suma de dinero o valores además de una fianza o garantía real. Los montos y condiciones serán determinados por la reglamentación.`,
    `Estas agencias deben dejar una garantía (caución) para responder por las obligaciones laborales.`),
  art('79', 'Sanciones a las empresas de servicios eventuales',
    `Las violaciones o incumplimientos por parte de las empresas de servicios eventuales serán sancionadas con multas, clausura o cancelación de habilitación para funcionar, sin perjuicio de las responsabilidades de la empresa usuaria por el artículo 29 bis de la Ley de Contrato de Trabajo.`,
    `Las agencias que incumplen pueden ser multadas, clausuradas o perder la habilitación, sin que ello libere a la empresa usuaria.`),
  art('80', 'Destino de la caución',
    `Si la empresa de servicios eventuales fuera sancionada con la cancelación de la habilitación, la caución no será devuelta y se destinará a satisfacer los créditos laborales de los trabajadores y los organismos de la seguridad social; el remanente irá al Fondo Nacional de Empleo. En los demás casos de cancelación, la caución será devuelta.`,
    `Si se cancela la habilitación de una agencia, su garantía se usa para pagar a los trabajadores y la seguridad social, y lo que sobre va al Fondo de Empleo.`),
  art('81', 'Programas para grupos con dificultades de inserción',
    `El Ministerio de Trabajo y Seguridad Social establecerá periódicamente programas destinados a fomentar el empleo de los trabajadores que presenten mayores dificultades de inserción laboral. Estos programas deberán atender a las características de los trabajadores a quienes van dirigidos y tendrán una duración determinada.`,
    `Faculta al Ministerio de Trabajo a crear programas de empleo para los grupos que más cuesta insertar laboralmente.`),
  art('82', 'Medidas de los programas',
    `Estos programas podrán contemplar, entre otras medidas: a) Actualización y reconversión profesional; b) Orientación y formación profesional; c) Asistencia en caso de movilidad geográfica; d) Asistencia técnica y financiera para iniciar pequeñas empresas, principalmente en forma asociada.`,
    `Lista las herramientas de esos programas: formación, reconversión, ayuda para mudarse por trabajo y apoyo para emprender.`),
  art('83', 'Programas para jóvenes desocupados',
    `Estos programas atenderán a las personas desocupadas entre catorce (14) y veinticuatro (24) años de edad. Las medidas deberán incluir capacitación y orientación profesionales gratuitas, complementadas con otras ayudas económicas cuando se consideren indispensables.`,
    `Programas específicos para jóvenes desocupados, con capacitación y orientación gratuitas.`),
  art('84', 'Programas para cesantes de difícil reinserción',
    `Estos programas se dirigirán a personas desocupadas que: a) tengan calificación en ocupaciones obsoletas o en vías de extinción; b) sean mayores de cincuenta (50) años; c) superen los ocho (8) meses de desempleo.`,
    `Programas para los que más cuesta reinsertar: mayores de 50, desempleados de larga duración o con oficios que ya no se usan.`),
  art('85', 'Programas para grupos protegidos',
    `Se considerará grupos protegidos a las personas mayores de catorce (14) años calificadas por los estatutos legales para liberados, aborígenes, ex-combatientes y rehabilitados de la drogadicción. Los empleadores que los contraten por tiempo indeterminado gozarán de la exención del artículo 46 por un año.`,
    `Crea programas para grupos protegidos (liberados, pueblos originarios, ex combatientes, rehabilitados), con beneficios para quien los contrate.`),
  art('86', 'Programas para personas con discapacidad',
    `Se considerará discapacitadas a las personas calificadas como tales según los artículos 2 y 3 de la ley 22.431, mayores de catorce años. Los programas contemplarán: a) talleres protegidos, trabajo a domicilio y prioridad en concesiones de bienes del Estado; b) el cumplimiento del cupo del cuatro por ciento (4 %) de personal con discapacidad en los organismos públicos; c) impulsar reservas de puestos en las convenciones colectivas del sector privado.`,
    `Programas para personas con discapacidad: talleres protegidos, prioridad en concesiones públicas y el cupo del 4% de empleo en el Estado.`),
  art('87', 'Incentivo por contratar personas con discapacidad',
    `Los empleadores que contraten trabajadores con discapacidad por tiempo indeterminado gozarán de la exención prevista en el artículo 46 sobre dichos contratos por el período de un (1) año, independientemente de las que establecen las leyes 22.431 y 23.031.`,
    `Quien contrate a una persona con discapacidad por tiempo indeterminado tiene un año de exención de contribuciones patronales.`),
  art('88', 'Créditos para suprimir barreras arquitectónicas',
    `Los empleadores que contraten un cuatro por ciento (4 %) o más de su personal con trabajadores discapacitados y deban emprender obras para suprimir barreras arquitectónicas gozarán de créditos especiales para su financiación.`,
    `Da créditos a las empresas que emplean al menos 4% de personas con discapacidad para adaptar sus instalaciones.`),
  art('89', 'Seguro de accidentes sin discriminación',
    `Los contratos de seguro de accidentes de trabajo no podrán discriminar ni en la prima ni en las condiciones, en razón de la calificación de discapacitado del trabajador asegurado.`,
    `La ART no puede cobrar más caro ni poner peores condiciones por asegurar a un trabajador con discapacidad.`),
  art('90', 'Reconversión de actividades informales',
    `Se establecerán programas dirigidos a apoyar la reconversión productiva de actividades informales para mejorar su productividad y gestión, y a nuevas iniciativas generadoras de empleo. Se considerarán actividades informales aquellas cuyo nivel de productividad esté por debajo de los valores que establezca el Consejo Nacional del Empleo, la Productividad y el Salario Mínimo, Vital y Móvil.`,
    `Crea programas para formalizar y hacer más productivas las actividades informales y para apoyar nuevos emprendimientos generadores de empleo.`),
  art('91', 'Promoción de pequeñas empresas y cooperativas',
    `En estos programas se promoverán la pequeña empresa, microemprendimientos, modalidades asociativas como cooperativas de trabajo, programas de propiedad participada, empresas juveniles y sociedades de propiedad de los trabajadores.`,
    `Esos programas fomentan pymes, microemprendimientos, cooperativas de trabajo y empresas de los propios trabajadores.`),
  art('92', 'Medidas de fomento de los emprendimientos',
    `Se establecerán, conjunta o alternativamente, las siguientes medidas de fomento: a) Simplificación registral y administrativa; b) Asistencia técnica; c) Formación y reconversión profesional; d) Capacitación en gestión; e) Fondos solidarios de garantía para acceder al crédito; f) Prioridad en el pago único de la prestación por desempleo del artículo 127.`,
    `Lista los apoyos a los nuevos emprendimientos: trámites simples, asistencia técnica, capacitación, garantías para créditos y el pago único del seguro de desempleo para emprender.`),
  art('93', 'Viabilidad económica de los proyectos',
    `Los proyectos que se incluyan en estos programas requerirán una declaración expresa de viabilidad económica formulada a partir de estudios técnicos específicos, por el Ministerio de Trabajo y Seguridad Social.`,
    `Para entrar en estos programas, el proyecto debe ser declarado económicamente viable por el Ministerio.`),
  art('94', 'Banco de proyectos',
    `El Ministerio de Trabajo y Seguridad Social deberá constituir y mantener un banco de proyectos, definir los lineamientos básicos para su diseño y brindar asistencia técnica para su ejecución y evaluación.`,
    `El Ministerio mantiene un "banco de proyectos" y asiste técnicamente a los emprendimientos.`),
  art('95', 'Declaración de reestructuración productiva',
    `El Ministerio de Trabajo y Seguridad Social podrá declarar en situación de reestructuración productiva, de oficio o a petición de parte, a las empresas públicas o mixtas, o sectores productivos, cuando se encuentren o pudieren encontrarse afectados por reducciones significativas del empleo.`,
    `Permite declarar a una empresa o sector "en reestructuración productiva" cuando hay riesgo de pérdida importante de empleo.`),
  art('96', 'Negociación en la reestructuración',
    `En la resolución que declare la reestructuración productiva, el Ministerio convocará a la comisión negociadora del convenio colectivo para negociar sobre: a) un programa de gestión preventiva del desempleo; b) las consecuencias en las condiciones de trabajo y empleo; c) medidas de reconversión y reinserción de los trabajadores. La comisión se expedirá en treinta (30) días. El empleador no podrá adoptar medidas que afecten el empleo hasta que se expida la comisión o venzan los plazos.`,
    `Declarada la reestructuración, se abre una negociación para prevenir el desempleo, y el empleador no puede tomar medidas que afecten el empleo mientras dura.`),
  art('97', 'Medidas en la reestructuración',
    `En los sectores declarados en reestructuración productiva, el Ministerio podrá: a) constituir una comisión técnica tripartita para estudiar la situación; b) autorizar a empresas no reestructuradas con más de veinticinco trabajadores a ampliar en un diez por ciento el límite del artículo 34 para contratar trabajadores afectados; c) elaborar un programa de empleo y reconversión profesional para los afectados.`,
    `Da herramientas para la reestructuración: estudios tripartitos, facilitar que otras empresas tomen a los trabajadores afectados y programas de reconversión.`),
  art('98', 'Procedimiento preventivo de crisis',
    `Con carácter previo a la comunicación de despidos o suspensiones por fuerza mayor, causas económicas o tecnológicas, que afecten a más del quince por ciento (15 %) de los trabajadores en empresas de menos de cuatrocientos; a más del diez por ciento (10 %) en empresas de entre cuatrocientos y mil; y a más del cinco por ciento (5 %) en empresas de más de mil, deberá sustanciarse el procedimiento preventivo de crisis previsto en este capítulo.`,
    `Antes de hacer despidos o suspensiones masivas (por encima de ciertos porcentajes según el tamaño de la empresa), el empleador debe abrir el "procedimiento preventivo de crisis" ante el Ministerio. Es una norma muy aplicada en crisis.`),
  art('99', 'Inicio del procedimiento de crisis',
    `El procedimiento de crisis se tramitará ante el Ministerio de Trabajo y Seguridad Social, a instancia del empleador o de la asociación sindical. En su presentación, el peticionante fundamentará su solicitud, ofreciendo los elementos probatorios pertinentes.`,
    `El procedimiento lo puede pedir el empleador o el sindicato, fundamentando la situación de crisis.`),
  art('100', 'Primera audiencia',
    `Dentro de las cuarenta y ocho (48) horas de efectuada la presentación, el Ministerio dará traslado a la otra parte y citará al empleador y al sindicato a una primera audiencia dentro de los cinco (5) días.`,
    `El Ministerio cita a las partes a una primera audiencia dentro de los 5 días.`),
  art('101', 'Período de negociación',
    `En caso de no existir acuerdo en la audiencia, se abrirá un período de negociación entre el empleador y la asociación sindical, que tendrá una duración máxima de diez (10) días.`,
    `Si no hay acuerdo en la audiencia, se negocia hasta 10 días.`),
  art('102', 'Facultades del Ministerio',
    `El Ministerio de Trabajo, de oficio o a petición de parte, podrá: a) Recabar informes aclaratorios o ampliatorios; b) Realizar investigaciones, pedir dictámenes y cualquier otra medida para mejor proveer.`,
    `El Ministerio puede pedir información e investigar durante el procedimiento.`),
  art('103', 'Acuerdo y homologación',
    `Si las partes arribaren a un acuerdo, lo elevarán al Ministerio, quien dentro de diez (10) días podrá: a) Homologar el acuerdo con la misma eficacia que un convenio colectivo; b) Rechazarlo mediante resolución fundada. Vencido el plazo sin pronunciamiento, el acuerdo se tendrá por homologado.`,
    `Si hay acuerdo, el Ministerio lo homologa (le da fuerza de convenio) o lo rechaza fundadamente; si no se expide, queda homologado.`),
  art('104', 'Prohibición de medidas durante el procedimiento',
    `A partir de la notificación y hasta la conclusión del procedimiento de crisis, el empleador no podrá ejecutar las medidas objeto del procedimiento, ni los trabajadores ejercer la huelga u otras medidas de acción sindical. La violación por el empleador determinará que los trabajadores mantengan su relación de trabajo y se les paguen los salarios caídos. Si los trabajadores ejercieren la huelga, se aplicará la ley 14.786.`,
    `Mientras dura el procedimiento, el empleador no puede despedir/suspender ni los trabajadores ir a la huelga. Si el empleador igual despide, los despidos no valen y debe pagar los salarios.`),
  art('105', 'Conclusión del procedimiento',
    `Vencidos los plazos previstos en este capítulo sin acuerdo de partes se dará por concluido el procedimiento de crisis.`,
    `Si vencen los plazos sin acuerdo, el procedimiento se cierra (y el empleador queda habilitado a tomar las medidas).`),
  art('106', 'Declaración de emergencia ocupacional',
    `El Ministerio de Trabajo y Seguridad Social podrá declarar la emergencia ocupacional de sectores productivos o regiones geográficas en atención a catástrofes naturales, razones económicas o tecnológicas.`,
    `Permite declarar la "emergencia ocupacional" de un sector o región afectada por catástrofes o crisis económicas.`),
  art('107', 'Requisitos de la emergencia ocupacional',
    `La declaración de la emergencia ocupacional podrá ser requerida por la autoridad local u organismo provincial competente o declarada de oficio. Las causales serán consideradas en cuanto tengan repercusión en los niveles de desocupación y subocupación de la zona, o cuando superen los promedios históricos locales una vez ajustadas las variaciones estacionales.`,
    `La emergencia la puede pedir la provincia o declararla el Ministerio, midiendo su impacto real en la desocupación de la zona.`),
  art('108', 'Programas de emergencia ocupacional',
    `Los programas de emergencia ocupacional consistirán en acciones tendientes a generar empleo masivo por un período determinado a través de contratación directa del Estado nacional, provincial y municipal para la ejecución de obras o servicios de utilidad pública e intensivos en mano de obra. El plazo mínimo de contratación se reducirá a tres (3) meses.`,
    `En la emergencia, el Estado genera empleo masivo y transitorio con obras y servicios públicos intensivos en mano de obra.`),
  art('109', 'Habilitación de modalidades en la emergencia',
    `Durante la vigencia de la emergencia, la autoridad de aplicación podrá habilitar las modalidades promovidas previstas en esta ley, mediante acto fundado. Esta habilitación concluirá al término del período de emergencia, manteniéndose los contratos promovidos vigentes hasta la finalización de su plazo.`,
    `[En gran parte sin efecto tras la derogación de las modalidades promovidas] Permitía usar las modalidades promovidas durante la emergencia.`),
  art('110', 'Beneficiarios de los programas de emergencia',
    `Los programas de emergencia ocupacional se ejecutarán en las zonas más pobladas dentro de la zona en emergencia y sus beneficiarios serán los residentes en las áreas más próximas a la ejecución de las obras, dándole prioridad a los trabajadores desocupados sin prestaciones por desempleo.`,
    `Los programas priorizan a los desocupados de la zona que no cobran seguro de desempleo.`),
  art('111', 'Ámbito de la protección por desempleo',
    `La protección que se instituye a través de la presente ley regirá en todo el territorio de la Nación de conformidad con sus disposiciones y las normas reglamentarias que se dicten.`,
    `El seguro de desempleo rige en todo el país.`),
  art('112', 'Trabajadores comprendidos',
    `Las disposiciones de este título serán de aplicación a todos los trabajadores cuyo contrato se rija por la Ley de Contrato de Trabajo. No será aplicable a los trabajadores del Régimen Nacional de Trabajo Agrario, del servicio doméstico y a quienes hayan dejado de prestar servicios en la Administración Pública por racionalización administrativa. El Poder Ejecutivo remitirá un proyecto que regulará las prestaciones por desempleo para los trabajadores de la construcción.`,
    `El seguro de desempleo cubre a los trabajadores de la LCT. Quedan afuera los rurales, el servicio doméstico y los estatales racionalizados (la construcción tiene su propio régimen).`),
  art('113', 'Requisitos para cobrar el seguro de desempleo',
    `Para tener derecho a las prestaciones por desempleo los trabajadores deberán: a) Encontrarse en situación legal de desempleo y disponibles para trabajar; b) Estar inscriptos en el Sistema Único de Registro Laboral; c) Haber cotizado al Fondo Nacional del Empleo un período mínimo de doce (12) meses durante los tres (3) años anteriores al cese; d) Los trabajadores eventuales, un período mínimo de noventa (90) días en los doce meses anteriores; e) No percibir beneficios previsionales ni prestaciones no contributivas; f) Haber solicitado la prestación en los plazos y formas que corresponda.`,
    `Para cobrar el seguro de desempleo hay que: estar legalmente desempleado y disponible, haber aportado al menos 12 meses en los últimos 3 años (90 días para eventuales), no cobrar jubilación ni pensión, y pedirlo en término.`),
  art('114', 'Situación legal de desempleo',
    `Se encontrarán bajo situación legal de desempleo los trabajadores comprendidos en: a) Despido sin justa causa (art. 245 LCT); b) Despido por fuerza mayor o falta o disminución de trabajo (art. 247 LCT); c) Resolución por denuncia del trabajador con justa causa (arts. 242 y 246 LCT); d) Extinción colectiva por motivo económico o tecnológico; e) Quiebra o concurso del empleador (art. 251 LCT); f) Expiración del tiempo convenido o fin de la obra; g) Muerte, jubilación o invalidez del empleador individual; h) No reiniciación del contrato de temporada por causas ajenas al trabajador. Ante duda sobre la relación o la causa, intervendrá la autoridad administrativa, sin que ello pueda hacerse valer en juicio laboral.`,
    `Define cuándo se considera "legalmente desempleado" a efectos del seguro: despido sin causa, por fuerza mayor, despido indirecto con causa, quiebra, fin del contrato a plazo, etc. No incluye la renuncia voluntaria ni el despido con justa causa.`),
  art('115', 'Plazo para solicitar la prestación',
    `La solicitud de la prestación deberá presentarse dentro del plazo de noventa (90) días a partir del cese de la relación laboral. Si se presentare fuera del plazo, los días que excedan serán descontados del total del período de prestación.`,
    `Tenés 90 días desde que perdés el trabajo para pedir el seguro; si te demorás, te descuentan los días de atraso del total a cobrar.`),
  art('116', 'Plazo de espera',
    `La percepción de las prestaciones comenzará a partir del cumplimiento de un plazo de sesenta (60) días corridos, que podrá ser reducido por el Consejo del Empleo. En los casos de trabajadores que hubieran percibido gratificaciones por cese dentro de los seis meses anteriores, el Consejo podrá establecer un período de espera diferenciado de hasta ciento veinte (120) días.`,
    `Hay un plazo de espera antes de empezar a cobrar (en la práctica, regulado por el Consejo). Si cobraste una gratificación por el despido, la espera puede ser mayor.`),
  art('117', 'Duración de las prestaciones',
    `El tiempo total de prestación estará en relación al período de cotización dentro de los tres años anteriores al cese, según la siguiente escala: de 12 a 23 meses de cotización, 4 meses de prestación; de 24 a 35 meses, 8 meses; 36 meses o más, 12 meses. Para los trabajadores eventuales, la duración será de un (1) día por cada tres (3) de servicios prestados con cotización, computándose contrataciones superiores a treinta días.`,
    `Cuánto tiempo cobrás el seguro depende de cuánto aportaste: con 12 a 23 meses, 4 meses de seguro; con 24 a 35, 8 meses; con 36 o más, 12 meses. Los eventuales cobran 1 día por cada 3 trabajados.`),
  art('118', 'Monto de la prestación',
    `La cuantía de la prestación será calculada como un porcentaje del importe neto de la mejor remuneración mensual, normal y habitual del trabajador en los seis meses anteriores al cese. El porcentaje de los primeros cuatro meses lo fija el Consejo Nacional del Empleo. Del quinto al octavo mes la prestación será el ochenta y cinco por ciento (85 %) de la de los primeros cuatro; del noveno al duodécimo, el setenta por ciento (70 %). En ningún caso podrá ser inferior al mínimo ni superior al máximo que fije el Consejo.`,
    `El monto del seguro es un porcentaje de tu mejor sueldo de los últimos 6 meses (lo fija el Consejo). Va bajando: del mes 5 al 8 cobrás el 85% de lo inicial, y del 9 al 12 el 70%, con un piso y un techo.`),
  art('119', 'Prestaciones que integran la protección',
    `Las siguientes prestaciones formarán parte de la protección por desempleo: a) La prestación económica por desempleo; b) Prestaciones médico-asistenciales según las leyes 23.660 y 23.661; c) Pago de las asignaciones familiares que correspondieren; d) Cómputo del período de las prestaciones a los efectos previsionales.`,
    `Además de la plata, mientras cobrás el seguro conservás la obra social, cobrás las asignaciones familiares y ese tiempo cuenta para la jubilación.`),
  art('120', 'Obligaciones de los empleadores',
    `Los empleadores están obligados a: a) Efectuar las inscripciones del artículo 7; b) Ingresar sus contribuciones al Fondo Nacional del Empleo; c) Ingresar los aportes de los trabajadores al Fondo como agente de retención; d) Proporcionar la documentación que se determine; e) Comprobar que el trabajador que cobraba seguro de desempleo cursó la baja al incorporarse.`,
    `Obligaciones del empleador frente al sistema: registrar al trabajador, aportar al Fondo de Empleo y verificar que quien cobraba seguro lo haya dado de baja al ser contratado.`),
  art('121', 'Obligaciones de los beneficiarios',
    `Los beneficiarios están obligados a: a) Proporcionar la documentación y comunicar cambios de domicilio; b) Aceptar los empleos adecuados ofrecidos y asistir a las acciones de formación; c) Aceptar los controles de la autoridad; d) Solicitar la extinción o suspensión del pago al incorporarse a un nuevo puesto; e) Reintegrar los montos indebidamente percibidos; f) Declarar las gratificaciones por cese de los últimos seis meses.`,
    `El que cobra el seguro debe: aceptar empleos adecuados y capacitarse, avisar si consigue trabajo (para dar de baja el seguro) y devolver lo cobrado de más.`),
  art('122', 'Suspensión de la prestación',
    `La percepción se suspenderá cuando el beneficiario: a) no comparezca sin justificación; b) no cumpla las obligaciones de los incisos a), b) y c) del art. 121; c) cumpla el servicio militar obligatorio, salvo cargas de familia; d) sea condenado con pena de prisión; e) celebre contrato de trabajo de duración determinada por menos de doce meses. La suspensión no afecta el período que le restaba percibir, que se reanuda al finalizar la causa.`,
    `El seguro se suspende (no se pierde) si el beneficiario no se presenta, incumple obligaciones, o toma un trabajo temporal de menos de 12 meses; al terminar esa situación, se reanuda el tiempo que faltaba.`),
  art('123', 'Extinción del derecho',
    `El derecho a la prestación se extinguirá cuando el beneficiario: a) agote el plazo de duración; b) obtenga beneficios previsionales o prestaciones no contributivas; c) celebre contrato de trabajo por más de doce meses; d) obtenga las prestaciones mediante fraude, simulación o reticencia; e) continúe percibiéndolas cuando correspondía la suspensión; f) incumpla las obligaciones de los incisos d) y e) del art. 121; g) no declare las gratificaciones por cese; h) se niegue reiteradamente a aceptar empleos adecuados.`,
    `El seguro se pierde definitivamente cuando se agota el plazo, conseguís un trabajo estable (más de 12 meses), te jubilás, lo obtuviste con fraude o rechazás reiteradamente empleos adecuados.`),
  art('124', 'Infracciones',
    `Las acciones u omisiones contrarias a las obligaciones de este capítulo serán consideradas infracciones y serán sancionadas conforme determine la reglamentación.`,
    `Incumplir las reglas del seguro de desempleo constituye una infracción sancionable.`),
  art('125', 'Procedimiento y recursos',
    `Las resoluciones de reconocimiento, suspensión, reanudación y extinción del derecho deberán fundarse y podrán recurrirse administrativa o judicialmente. La denegatoria expresa puede recurrirse ante la Cámara Nacional de Apelaciones de la Seguridad Social en 30 días. Si no recae resolución en 45 días y, tras pronto despacho, transcurren otros 30 sin resolver, hay silencio de la administración y queda expedita la vía judicial. Supletoriamente rige la ley 19.549 de Procedimientos Administrativos.`,
    `Las decisiones sobre el seguro deben fundarse y se pueden apelar ante la Cámara de la Seguridad Social; si la administración no resuelve en los plazos, se habilita la vía judicial.`),
  art('126', 'Aumento de la duración',
    `El Ministerio de Trabajo y Seguridad Social, como autoridad de aplicación, tendrá facultades para aumentar la duración de las prestaciones conforme a las disponibilidades financieras del sistema.`,
    `El Ministerio puede extender la duración del seguro si el sistema tiene fondos.`),
  art('127', 'Pago único como fomento del empleo',
    `La reglamentación contemplará la modalidad de pago único de las prestaciones como medida de fomento del empleo, para beneficiarios que se constituyan como trabajadores asociados o miembros de cooperativas de trabajo u otras formas de trabajo asociado, en actividades productivas.`,
    `Permite cobrar todo el seguro de desempleo de una sola vez para usarlo como capital y emprender (por ejemplo, en una cooperativa de trabajo).`),
  art('128', 'Programas de formación profesional para el empleo',
    `El Ministerio de Trabajo y Seguridad Social deberá elaborar programas de formación profesional para el empleo que incluirán acciones de formación, calificación, capacitación, reconversión, perfeccionamiento y especialización de los trabajadores tendientes a apoyar y facilitar: a) creación de empleo productivo; b) reinserción de los desocupados; c) reasignación por reformas del sector público y reconversión; d) el primer empleo de los jóvenes; e) la mejora de la productividad y la formalización de actividades informales.`,
    `El Ministerio debe crear programas de formación profesional para crear empleo, reinsertar desocupados y capacitar a los jóvenes en su primer empleo.`),
  art('129', 'Atribuciones en formación profesional',
    `Serán atribuciones del Ministerio de Trabajo: a) integrar la formación profesional a la política laboral; b) coordinar programas con el sector público y privado mediante convenios; c) validar la certificación de calificaciones; d) formular los programas de alternancia de formación y práctica laboral.`,
    `Faculta al Ministerio a coordinar y certificar la formación profesional con los sectores público y privado.`),
  art('130', 'Red de Servicios de Empleo',
    `El Ministerio de Trabajo y Seguridad Social organizará y coordinará la Red de Servicios de Empleo, gestionará los programas de intermediación, fomento y promoción del empleo y llevará el registro de trabajadores desocupados.`,
    `Crea la Red de Servicios de Empleo, que conecta oferta y demanda laboral y registra a los desocupados (las actuales oficinas de empleo).`),
  art('131', 'Función de la Red de Servicios de Empleo',
    `La Red de Servicios de Empleo tendrá como función la coordinación de la gestión operativa de los Servicios de Empleo a fin de garantizar la ejecución en todo el territorio nacional de las políticas del sector.`,
    `La Red coordina los servicios de empleo en todo el país.`),
  art('132', 'Integración de las provincias a la Red',
    `Las provincias podrán integrarse a la Red de Servicios de Empleo por medio de convenios con el Ministerio, tendiendo a la descentralización municipal de la gestión. El Ministerio promoverá la integración de organizaciones empresariales, sindicales y sin fines de lucro.`,
    `Las provincias y municipios se suman a la Red por convenio, y también participan empresas y sindicatos.`),
  art('133', 'Estadísticas laborales',
    `El Ministerio de Trabajo diseñará y ejecutará programas de estadísticas e información laboral, coordinados con el INDEC e integrados al Sistema Estadístico Nacional. A tal fin elaborará encuestas, organizará un banco de datos e intervendrá en el diseño de los censos y encuestas oficiales sobre empleo, formación, ingresos y productividad.`,
    `Encarga al Ministerio las estadísticas laborales, en coordinación con el INDEC.`),
  art('134', 'Información para el Consejo',
    `El Ministerio de Trabajo suministrará al Consejo Nacional del Empleo, la Productividad y el Salario Mínimo, Vital y Móvil la información necesaria, y coordinará con el INDEC el seguimiento de los precios y la valorización mensual de la canasta básica.`,
    `El Ministerio le da al Consejo del Salario los datos para fijar el salario mínimo, incluida la canasta básica.`),
  art('135', 'Consejo Nacional del Empleo, la Productividad y el Salario Mínimo, Vital y Móvil',
    `Créase el Consejo Nacional del Empleo, la Productividad y el Salario Mínimo, Vital y Móvil con las funciones de: a) determinar periódicamente el salario mínimo, vital y móvil; b) determinar los montos mínimo y máximo y el porcentaje del art. 118 del seguro de desempleo; c) aprobar la metodología de la canasta básica; d) constituir comisiones técnicas tripartitas sectoriales; e) fijar las pautas de las actividades informales; f) formular recomendaciones de políticas de empleo; g) proponer medidas para incrementar la producción y la productividad.`,
    `Crea el Consejo del Salario, el organismo tripartito (Estado, empleadores y trabajadores) que fija el salario mínimo, vital y móvil y los parámetros del seguro de desempleo.`),
  art('136', 'Integración del Consejo',
    `El Consejo estará integrado por dieciséis (16) representantes de los empleadores y dieciséis (16) de los trabajadores, ad-honorem, designados por el Poder Ejecutivo, y por un presidente designado por el Ministerio de Trabajo, durando cuatro (4) años. La representación de los empleadores incluye al Estado nacional y a las provincias adheridas; la de los trabajadores, a la central con personería gremial.`,
    `El Consejo del Salario tiene 16 representantes de los empleadores y 16 de los trabajadores, más un presidente del Ministerio.`),
  art('137', 'Decisiones del Consejo',
    `Las decisiones del Consejo serán tomadas por mayoría de dos tercios. En caso de no lograrse al término de dos sesiones, su presidente laudará respecto de los puntos en controversia.`,
    `El Consejo decide por dos tercios; si no hay acuerdo en dos sesiones, decide el presidente (laudo).`),
  art('138', 'Modificación del salario mínimo',
    `A petición de cualquiera de los sectores representados en el Consejo, se podrá modificar el monto del salario mínimo, vital y móvil establecido.`,
    `Cualquiera de las partes del Consejo puede pedir que se revise el salario mínimo.`),
  art('139', 'Salario mínimo, vital y móvil',
    `El salario mínimo, vital y móvil garantizado por el artículo 14 bis de la Constitución Nacional y previsto por el artículo 116 de la Ley de Contrato de Trabajo será determinado por el Consejo Nacional del Empleo, la Productividad y el Salario Mínimo, Vital y Móvil teniendo en cuenta los datos de la situación socioeconómica, los objetivos del instituto y la razonabilidad de la adecuación entre ambos.`,
    `Define quién fija el salario mínimo, vital y móvil (el "SMVM"): el Consejo del Salario, según la situación económica. Es el piso salarial de toda la economía.`),
  art('140', 'Derecho al salario mínimo',
    `Todos los trabajadores comprendidos en la Ley de Contrato de Trabajo, de la Administración Pública Nacional y de las entidades en que el Estado nacional actúe como empleador, tendrán derecho a percibir una remuneración no inferior al salario mínimo, vital y móvil.`,
    `Ningún trabajador puede cobrar menos que el salario mínimo, vital y móvil.`),
  art('141', 'El SMVM no es índice de otros institutos',
    `El salario mínimo, vital y móvil no podrá ser tomado como índice o base para la determinación cuantitativa de ningún otro instituto legal o convencional.`,
    `El salario mínimo no puede usarse como referencia para calcular otras cosas (multas, topes, etc.).`),
  art('142', 'Vigencia del salario mínimo',
    `El salario mínimo, vital y móvil tendrá vigencia y será de aplicación obligatoria a partir del primer día del mes siguiente de la publicación. Excepcionalmente, se podrá disponer que entre en vigencia al día siguiente de su publicación. En todos los casos deberá publicarse en el Boletín Oficial.`,
    `El nuevo salario mínimo rige desde el mes siguiente a su publicación (o al día siguiente en casos excepcionales).`),
  art('143', 'Creación del Fondo Nacional del Empleo',
    `Créase el Fondo Nacional del Empleo, con el objeto de proveer al financiamiento de los institutos, programas, acciones, sistemas y servicios contemplados en la presente ley.`,
    `Crea el Fondo Nacional del Empleo, que financia el seguro de desempleo y los programas de empleo.`),
  art('144', 'Recursos del Fondo (tipos)',
    `El Fondo Nacional del Empleo se constituirá con dos tipos de recursos: a) Aportes y contribuciones del artículo 145 inciso a), para financiar el Sistema Integral de Prestaciones por Desempleo; b) Los recursos de los incisos b) y c) del artículo siguiente, para financiar los programas de generación de empleo y los servicios del Ministerio.`,
    `El Fondo se divide en dos: lo que financia el seguro de desempleo y lo que financia los programas de empleo.`),
  art('145', 'Recursos del Fondo (detalle)',
    `Los recursos del Fondo Nacional del Empleo son: a) Aportes y contribuciones: 1,5 puntos de la contribución a las cajas de asignaciones familiares; una contribución del 3 % de las remuneraciones pagadas por las empresas de servicios eventuales; una contribución del 0,5 % a cargo del empleador privado y un aporte del 0,5 % a cargo del trabajador; b) Aportes del Estado (presupuesto, provincias y municipios); c) Otros recursos (donaciones, rentas, multas, saldos no utilizados y cooperación internacional).`,
    `Detalla cómo se financia el Fondo de Empleo: con parte de las contribuciones de asignaciones familiares, aportes del empleador y del trabajador, fondos del presupuesto y otros recursos.`),
  art('146', 'Modificación del aporte de asignaciones familiares',
    `Sustitúyese el artículo 23 de la ley 18.017 (modificado por la ley 23.568): fíjase como aporte obligatorio de los empleadores el nueve por ciento (9 %) sobre el total de las remuneraciones, incluido el aguinaldo. De ese 9 %, un punto y medio (1,5) se destina al Fondo Nacional del Empleo y los siete y medio (7,5) restantes a la Caja de Asignaciones Familiares.`,
    `Fijó la contribución patronal de asignaciones familiares en 9%, de los cuales 1,5 puntos van al Fondo Nacional del Empleo.`),
  art('147', 'Recaudación de los recursos del Fondo',
    `La recaudación de los aportes y contribuciones del artículo 145 será efectivizada a través de las Cajas de Subsidios y Asignaciones Familiares, las que tendrán las mismas facultades de cobro que las leyes 18.017 y 22.161.`,
    `Las cajas de asignaciones familiares recaudan los aportes del Fondo de Empleo.`),
  art('148', 'Transferencia de lo recaudado',
    `Las Cajas de Subsidios Familiares transferirán a la cuenta del Fondo Nacional del Empleo, en el plazo de cinco (5) días de su recaudación, las sumas percibidas conforme a los artículos 145 y 146.`,
    `Las cajas transfieren al Fondo lo recaudado dentro de los 5 días.`),
  art('149', 'Cuenta especial del Fondo',
    `El Fondo Nacional del Empleo se constituirá como Cuenta Especial presupuestaria en jurisdicción del Ministerio de Trabajo y Seguridad Social. Las sumas recaudadas no podrán destinarse a otro fin que el expresamente dispuesto en esta ley.`,
    `El Fondo es una cuenta especial del Ministerio de Trabajo, y su plata solo puede usarse para los fines de esta ley.`),
  art('150', 'Administración del Fondo',
    `El Ministerio de Trabajo y Seguridad Social tendrá a su cargo la administración y gestión del Fondo Nacional del Empleo. El pago de las prestaciones, la recaudación de los aportes y su control estarán a cargo de las cajas de asignaciones y subsidios familiares.`,
    `El Ministerio administra el Fondo; las cajas familiares pagan las prestaciones y controlan la recaudación.`),
  art('151', 'Comisión Bicameral de control',
    `Créase una Comisión Bicameral integrada por tres (3) Senadores y tres (3) Diputados, con la función de supervisar el cumplimiento de la presente ley, facultada para requerir información de los organismos gestores y de la autoridad de aplicación.`,
    `Crea una comisión del Congreso (3 senadores y 3 diputados) para controlar el cumplimiento de la ley.`),
  art('152', 'Prestación transitoria por desempleo',
    `Institúyese una prestación por desempleo con carácter transitorio hasta tanto comience a efectivizarse el beneficio del Título IV. Los requisitos, plazos y montos serán establecidos por la reglamentación. El pago deberá comenzar en un plazo no mayor de noventa (90) días de sancionada la ley.`,
    `Disposición de 1991: creó un seguro de desempleo transitorio hasta que arrancara el definitivo del Título IV.`),
  art('153', 'Modificación del art. 245 LCT (indemnización por despido)',
    `Sustitúyese el artículo 245 de la Ley de Contrato de Trabajo por el siguiente: "Artículo 245. Indemnización por antigüedad o despido. En los casos de despido dispuesto por el empleador sin justa causa, deberá abonar al trabajador una indemnización equivalente a un (1) mes de sueldo por cada año de servicio o fracción mayor de tres (3) meses, tomando como base la mejor remuneración mensual, normal y habitual percibida durante el último año o durante el tiempo de prestación de servicios si este fuera menor. Dicha base no podrá exceder el equivalente de tres (3) veces el importe mensual del promedio de las remuneraciones del convenio colectivo aplicable. El importe de esta indemnización en ningún caso podrá ser inferior a dos (2) meses de sueldo."`,
    `Reformó el artículo 245 de la LCT, el más importante del derecho laboral: la indemnización por despido sin causa es de 1 sueldo por año trabajado (o fracción mayor a 3 meses), tomando el mejor sueldo del último año, con un tope ("tope Vizzoti") y un piso de 2 sueldos. Sigue vigente.`),
  art('154', 'Derogaciones (emergencia económica)',
    `Derógase el artículo 48 de la ley 23.697 de emergencia económica, y el artículo 19 de la ley 23.769.`,
    `Deroga dos normas de la emergencia económica de fines de los 80.`),
  art('155', 'Modificación de la indemnización en el trabajo agrario',
    `Sustitúyese el inciso a) del artículo 76 de la ley 22.248 (régimen de trabajo agrario): un (1) mes de sueldo por cada año de servicio o fracción mayor de tres meses, tomando la mejor remuneración mensual normal y habitual, con un tope de tres veces el promedio de las remuneraciones de la Comisión Nacional de Trabajo Agrario y un piso de dos meses.`,
    `Aplicó la misma fórmula de indemnización por despido del art. 245 LCT al régimen de trabajo agrario de la época.`),
  art('156', 'Exigibilidad de aportes y contribuciones',
    `Los aportes y contribuciones establecidos por el título VIII de la presente ley serán exigibles a partir de los sueldos devengados desde el primer día del mes siguiente al de vigencia de la presente ley.`,
    `Los aportes al Fondo de Empleo se empezaron a cobrar desde el mes siguiente a la vigencia de la ley.`),
  art('157', 'Inicio del seguro de desempleo',
    `El Sistema Integral de Prestaciones por Desempleo comenzará a efectivizar las prestaciones del Título IV a los ciento ochenta (180) días de dictada la presente ley. El requisito del inciso c) del artículo 113 podrá ser acreditado conforme lo establezca la reglamentación.`,
    `El seguro de desempleo definitivo empezó a pagarse 180 días después de la ley.`),
  art('158', 'Convenios con las provincias',
    `Facúltase al Poder Ejecutivo Nacional para gestionar con los gobiernos provinciales la firma de convenios y acuerdos necesarios para la ejecución de esta ley.`,
    `Habilita al Poder Ejecutivo a firmar convenios con las provincias para aplicar la ley.`),
  art('159', 'Derogación general',
    `Derógase toda disposición que se oponga a la presente ley.`,
    `Deroga toda norma anterior que contradiga esta ley.`),
  art('160', 'Comunicación',
    `Comuníquese al Poder Ejecutivo.`,
    `Fórmula final de comunicación de la ley al Poder Ejecutivo.`),
];

